mapper.sql:
WHERE 1 = 1
AND ( ac.company_name LIKE CONCAT('%', #{criteria.keyword}, '%') OR ac.job_title LIKE CONCAT('%', #{criteria.keyword}, '%') OR u.email LIKE CONCAT('%', #{criteria.keyword}, '%') OR ja.summary LIKE CONCAT('%', #{criteria.keyword}, '%') OR ja.duties LIKE CONCAT('%', #{criteria.keyword}, '%') OR ja.qualifications LIKE CONCAT('%', #{criteria.keyword}, '%') OR CAST(ja.required_skills AS CHAR) LIKE CONCAT('%', #{criteria.keyword}, '%') OR CAST(ja.preferred_skills AS CHAR) LIKE CONCAT('%', #{criteria.keyword}, '%') )
AND UPPER(ja.difficulty) = #{criteria.difficulty}
AND ja.confirmed_at IS NOT NULL
AND ja.confirmed_at IS NULL
AND ja.admin_memo IS NOT NULL AND TRIM(ja.admin_memo) <> ''
AND (ja.admin_memo IS NULL OR TRIM(ja.admin_memo) = '')
AND ja.application_case_id = #{criteria.applicationCaseId}
AND ac.user_id = #{criteria.userId}
AND ja.created_at >= #{criteria.createdFrom}
AND ja.created_at < DATE_ADD(#{criteria.createdTo}, INTERVAL 1 DAY)
